class Solution:
    def canChange(self, start, target):
        # BFS over reachable strings is exponential; instead use a clearly-correct
        # invariant check independent of the optimized two-pointer: every move is
        # an adjacent swap of a piece with a blank in its allowed direction, which
        # preserves (a) the order of non-blank chars and (b) for the k-th piece,
        # L can only decrease its index and R can only increase it.
        s_pieces = [(c, i) for i, c in enumerate(start) if c != '_']
        t_pieces = [(c, i) for i, c in enumerate(target) if c != '_']
        if len(s_pieces) != len(t_pieces):
            return False
        for (sc, si), (tc, ti) in zip(s_pieces, t_pieces):
            if sc != tc:
                return False
            if sc == 'L' and si < ti:
                return False
            if sc == 'R' and si > ti:
                return False
        return True

